#include "htif.h"

#include <stddef.h>

#define SYSCALL_0(num) \
  frontend_syscall(num, 0, 0, 0, 0, 0, 0, 0)

#define SYSCALL_1(num, a0) \
  frontend_syscall(num, (uintptr_t)(a0), 0, 0, 0, 0, 0, 0)

#define SYSCALL_2(num, a0, a1) \
  frontend_syscall(num, (uintptr_t)(a0), (uintptr_t)(a1), 0, 0, 0, 0, 0)

#define SYSCALL_3(num, a0, a1, a2) \
  frontend_syscall(num, (uintptr_t)(a0), (uintptr_t)(a1), (uintptr_t)(a2), 0, 0, 0, 0)

#define SYSCALL_4(num, a0, a1, a2, a3) \
  frontend_syscall(num, (uintptr_t)(a0), (uintptr_t)(a1), (uintptr_t)(a2), (uintptr_t)(a3), 0, 0, 0)

#define DISPLAY_BASE_ADDR 0xe0080004
#define EXIT_COMMAND_ADDR 0xe0080000
#define EXIT_SUCCESS_CODE 0x01234568
#define EXIT_FAILURE_CODE 0x01234569
#include <stdint.h>
#include <stdio.h>
#include <sys/stat.h>
#include <sys/time.h>
#include <sys/types.h>
#include <time.h>
#include <unistd.h>

__attribute__((used)) int _gettimeofday(struct timeval* tp,
                                           void* tzp __attribute__((unused)))
{
  return SYSCALL_2(5, tp, tzp);
}

__attribute__((used)) int _open(const char* name __attribute__((unused)),
                                   int flags,
                                   int permission,
                                   ...)
{
  return SYSCALL_3(6, name, flags, permission);
}

__attribute__((used)) ssize_t _write(int fd __attribute__((unused)),
                                        const void* ptr,
                                        size_t len)
{
  if (fd > 2) {
    return SYSCALL_3(7, fd, ptr, len);
  }

  volatile uint8_t* display = (volatile uint8_t*) DISPLAY_BASE_ADDR;
  for (size_t i = 0; i < len; ++i)
    *display = *((uint8_t*) ptr + i);
  return len;
}

__attribute__((used)) int _getcwd(const char* name __attribute__((unused)),
                                     int size,
                                     ...)
{
  return SYSCALL_2(8, name, size);
}

__attribute__((used)) ssize_t _lseek(int fd, int offset, int dir)
{
  return SYSCALL_3(9, fd, offset, dir);
}

__attribute__((used)) ssize_t _read(int fd, void* buf, int len)
{
  return SYSCALL_3(10, fd, buf, len);
}

__attribute__((used)) int _flen(int fd)
{
  return SYSCALL_1(11, fd);
}

__attribute__((used)) int _close(int fd __attribute__((unused)))
{
  if (fd <= 2) {
    return 0;
  }
  return SYSCALL_1(12, fd);
}

__attribute__((used)) int _access(const char* file, int mode)
{
  return SYSCALL_2(13, file, mode);
}

__attribute__((used)) int
_faccessat(int dirfd, const char* file, int mode, int flags)
{
  return SYSCALL_4(14, dirfd, file, mode, flags);
}

__attribute__((used)) int _fstat(int fd, struct stat* st)
{
  return SYSCALL_2(15, fd, st);
}
__attribute__((used)) int
_fstatat(int dirfd, const char* file, struct stat* st, int flags)
{
  return SYSCALL_4(16, dirfd, file, st, flags);
}

__attribute__((used)) int _link(const char* old_name, const char* new_name)
{
  return SYSCALL_2(17, old_name, new_name);
}

__attribute__((used)) int _lstat(const char* file, struct stat* st)
{
  return SYSCALL_2(18, file, st);
}
__attribute__((used)) int _stat(const char* file, struct stat* st)
{
  return SYSCALL_2(19, file, st);
}
__attribute__((used)) int
_openat(int dirfd, const char* name, int flags, ...)
{
  return SYSCALL_3(20, dirfd, name, flags);
}

__attribute__((used)) int _rename(const char* old_name, const char* new_name)
{
  return SYSCALL_2(21, old_name, new_name);
}

__attribute__((used)) int _unlink(const char* file_name)
{
  return SYSCALL_1(22, file_name);
}

__attribute__((used, noreturn)) void _exit(int exit_status)
{
  volatile uint32_t* command = (volatile uint32_t*) EXIT_COMMAND_ADDR;
  *command = exit_status;
  __asm__ __volatile__("1: j 1b");
  __builtin_unreachable();
}

__attribute__((used)) void* _sbrk(intptr_t increment)
{
  extern char _end[];
  static char* p = _end;
  void* base = p;
  p += increment;
  return base;
}

#ifdef __cplusplus
}
#endif

