33	{
34	  FINISHED = 0x01234567,
35	  PASSED = 0x01234568,
36	  FAILED = 0x01234569,
37	  WARNING = 0x01234570,
38	  SKIPPED = 0x01234571,
39	  NEWLINE = 0xddddeeee,
