51	class sim_control : public sc_core::sc_module, public PeTarget
52	{
53	public:
54	  using sys_func_ptr = uint64_t (sim_control::*)(
55	    uint64_t, uint64_t, uint64_t, uint64_t, uint64_t, uint64_t, uint64_t);
