94	  unsigned handle_trans(tlm::tlm_generic_payload& trans)
95	  {
96	    const auto addr = trans.get_address();
97	    const auto len = trans.get_data_length();
98	    const auto buf = std::span{trans.get_data_ptr(), len};
99	
100	    if (trans.is_read()) {
101	      spdlog::debug("sim transaction: read, addr={:#x}, len={}", addr, len);
102	      trans.set_response_status(tlm::TLM_OK_RESPONSE);
103	      return 0;
104	    }
105	
106	    spdlog::debug("sim transaction: write, addr={:#x}, len={}", addr, len);
107	
108	    if (addr == region.base_address && len == 4) {
109	      handle_sim_command(unpack<uint32_t>(buf));
110	    } else if (addr == region.base_address + HTIF_PUTCHAR_OFFSET && len == 1) {
111	      std::putchar(buf[0]);
112	    } else if (addr == region.base_address + HTIF_CMD_OFFSET) {
113	      (len == 8) ? handle_htif_64bit_write(buf)
114	                 : handle_htif_32bit_low_write(buf);
115	    } else if (addr == region.base_address + HTIF_CMD_HIGH_OFFSET && len == 4) {
116	      handle_htif_32bit_high_write(buf);
117	    } else {
118	      spdlog::warn("sim_control: spurious write at {:#x}, length {}", addr,
119	                   len);
120	    }
121	
122	    trans.set_response_status(tlm::TLM_OK_RESPONSE);
