126	#if ENABLE_PYBIND11
127	  static void bind_pybind11(pybind11::module_& m)
128	  {
129	    char namebuf[30];
130	    snprintf(namebuf, sizeof(namebuf), "sim_control_%s_%lu", PeTarget::name,
131	             PeTarget::bus_width);
132	    pybind11::class_<sim_control>(m, namebuf)
133	      .def_readwrite("exits", &sim_control::exits);
134	  }
135	#endif
