137	public:
138	  int32_t exits; // exit code
139	  const memory_region region;
140	
141	private:
142	  memory<PeTarget>& data_region;
143	  sys_func_ptr sim_syscall_table[SYSCALL_TABLE_SIZE];
144	  uint32_t riscv_xlen;
145	  uint64_t partial_htif_command;
146	  int htif_parts_received;
147	
148	  void handle_sim_command(uint32_t command)
149	  {
150	    switch (static_cast<SimCommand>(command)) {
151	    case SimCommand::NEWLINE:
152	      std::putchar('\n');
153	      break;
154	    case SimCommand::TEST_ILM:
155	      subport_test = SubPortTest::TEST_ILM;
156	      custom_master_sem.post();
157	      break;
158	    case SimCommand::TEST_DLM:
159	      subport_test = SubPortTest::TEST_DLM;
160	      custom_master_sem.post();
161	      break;
162	    case SimCommand::TEST_HVM:
163	      subport_test = SubPortTest::TEST_HVM;
164	      custom_master_sem.post();
165	      break;
166	    default:
167	      if (command >= 0 && command < 256)
168	        exits = command;
169	      else
