176	  {
177	    T result = 0;
178	    for (size_t i = 0; i < sizeof(T); ++i)
179	      result |= static_cast<T>(buf[i]) << (i * 8);
180	    return result;
181	  }
182	
183	  void execute_htif_syscall()
184	  {
185	    command_t cmd(partial_htif_command);
186	    if (cmd.device() != 0 || cmd.cmd() != 0) {
187	      spdlog::warn("unknown device: #{}", cmd.device());
188	      return;
189	    }
190	    dispatch(cmd);
191	    partial_htif_command = 0;
192	    htif_parts_received = 0;
193	  }
194	
195	  void handle_htif_64bit_write(const std::span<uint8_t>& buf)
196	  {
197	    command_t cmd(unpack<uint64_t>(buf));
198	    if (cmd.device() == 0 && cmd.cmd() == 0)
199	      dispatch(cmd);
200	    else
201	      spdlog::warn("unknown device: #{}", cmd.device());
202	  }
203	
204	  void handle_htif_32bit_low_write(const std::span<uint8_t>& buf)
205	  {
206	    partial_htif_command |= unpack<uint32_t>(buf);
207	    if (++htif_parts_received == HTIF_32BIT_PARTS)
208	      execute_htif_syscall();
209	  }
210	
211	  void handle_htif_32bit_high_write(const std::span<uint8_t>& buf)
212	  {
213	    partial_htif_command |= static_cast<uint64_t>(unpack<uint32_t>(buf)) << 32;
214	    if (++htif_parts_received == HTIF_32BIT_PARTS)
215	      execute_htif_syscall();
216	  }
217	
218	  void dispatch(command_t cmd)
219	  {
220	    uint64_t syscall_args[MAGIC_MEM_SIZE];
221	    auto addr_offset = cmd.payload() - data_region.region.base_address;
222	    auto src = data_region.data.begin() + addr_offset;
223	
224	    std::copy(src, src + sizeof(syscall_args),
225	              reinterpret_cast<uint8_t*>(syscall_args));
226	
227	    syscall_args[0] = (this->*sim_syscall_table[syscall_args[0]])(
228	      syscall_args[1], syscall_args[2], syscall_args[3], syscall_args[4],
229	      syscall_args[5], syscall_args[6], syscall_args[7]);
230	
231	    std::copy(reinterpret_cast<uint8_t*>(syscall_args),
232	              reinterpret_cast<uint8_t*>(syscall_args) + sizeof(syscall_args),
233	              src);
234	  }
