#ifndef SIM_CONTROL_HPP
#define SIM_CONTROL_HPP

#include "custom_master.hpp"
#include "htif/command.hpp"
#include "htif/picolib.hpp"
#include "memory.hpp"
#include "memory_region.hpp"
#include "pybind11.hpp"
#include "utils/bus_types.hpp"

#include <axi/axi_tlm.h>
#include <axi/pe/simple_target.h>
#include <fcntl.h>
#include <spdlog/spdlog.h>
#include <systemc>
#include <tlm>
#include <unistd.h>

#include <cstdint>

#include <span>

// Offsets relative to region.base_address
#define HTIF_CMD_OFFSET 0x10
#define HTIF_CMD_HIGH_OFFSET 0x14
#define HTIF_PUTCHAR_OFFSET 0x4

extern sc_core::sc_semaphore custom_master_sem;
extern SubPortTest subport_test;

enum class SimCommand : uint32_t
{
  FINISHED = 0x01234567,
  PASSED = 0x01234568,
  FAILED = 0x01234569,
  WARNING = 0x01234570,
  SKIPPED = 0x01234571,
  NEWLINE = 0xddddeeee,
  // below are for tests only
  TEST_ILM = 0x00abcde0,
  TEST_DLM = 0x00abcde1,
  TEST_HVM = 0x00abcde2
};

constexpr size_t SYSCALL_TABLE_SIZE = 100;
constexpr size_t MAGIC_MEM_SIZE = 8;
constexpr int HTIF_32BIT_PARTS = 2;

template<PeTargetType PeTarget>
class sim_control : public sc_core::sc_module, public PeTarget
{
public:
  using sys_func_ptr = uint64_t (sim_control::*)(
    uint64_t, uint64_t, uint64_t, uint64_t, uint64_t, uint64_t, uint64_t);

  sim_control(const sc_core::sc_module_name& name,
              const memory_region& region,
              memory<PeTarget>& main_memory)
      : sc_core::sc_module{name},
        exits(-1),
        region(region),
        data_region(main_memory),
        riscv_xlen(0),
        partial_htif_command(0),
        htif_parts_received(0)
  {

    sim_syscall_table[5] = &sim_control::handle_gettimeofday;
    sim_syscall_table[6] = &sim_control::handle_open;
    sim_syscall_table[7] = &sim_control::handle_write;
    sim_syscall_table[8] = &sim_control::handle_getcwd;
    sim_syscall_table[9] = &sim_control::handle_lseek;
    sim_syscall_table[10] = &sim_control::handle_read;
    sim_syscall_table[11] = &sim_control::handle_flen;
    sim_syscall_table[12] = &sim_control::handle_close;
    sim_syscall_table[13] = &sim_control::handle_access;
    sim_syscall_table[14] = &sim_control::handle_faccessat;
    sim_syscall_table[15] = &sim_control::handle_fstat;
    sim_syscall_table[16] = &sim_control::handle_fstatat;
    sim_syscall_table[17] = &sim_control::handle_link;
    sim_syscall_table[18] = &sim_control::handle_lstat;
    sim_syscall_table[19] = &sim_control::handle_stat;
    sim_syscall_table[20] = &sim_control::handle_openat;
    sim_syscall_table[21] = &sim_control::handle_rename;
    sim_syscall_table[22] = &sim_control::handle_unlink;

    this->protocol_engine.set_operation_cb(
      [this](auto& trans) { return this->handle_trans(trans); });
  }

#include "htif/sys_call.hpp"

  unsigned handle_trans(tlm::tlm_generic_payload& trans)
  {
    const auto addr = trans.get_address();
    const auto len = trans.get_data_length();
    const auto buf = std::span{trans.get_data_ptr(), len};

    if (trans.is_read()) {
      spdlog::debug("sim transaction: read, addr={:#x}, len={}", addr, len);
      trans.set_response_status(tlm::TLM_OK_RESPONSE);
      return 0;
    }

    spdlog::debug("sim transaction: write, addr={:#x}, len={}", addr, len);

    if (addr == region.base_address && len == 4) {
      handle_sim_command(unpack<uint32_t>(buf));
    } else if (addr == region.base_address + HTIF_PUTCHAR_OFFSET && len == 1) {
      std::putchar(buf[0]);
    } else if (addr == region.base_address + HTIF_CMD_OFFSET) {
      (len == 8) ? handle_htif_64bit_write(buf)
                 : handle_htif_32bit_low_write(buf);
    } else if (addr == region.base_address + HTIF_CMD_HIGH_OFFSET && len == 4) {
      handle_htif_32bit_high_write(buf);
    } else {
      spdlog::warn("sim_control: spurious write at {:#x}, length {}", addr,
                   len);
    }

    trans.set_response_status(tlm::TLM_OK_RESPONSE);
    return 0;
  }

#if ENABLE_PYBIND11
  static void bind_pybind11(pybind11::module_& m)
  {
    char namebuf[30];
    snprintf(namebuf, sizeof(namebuf), "sim_control_%s_%lu", PeTarget::name,
             PeTarget::bus_width);
    pybind11::class_<sim_control>(m, namebuf)
      .def_readwrite("exits", &sim_control::exits);
  }
#endif

public:
  int32_t exits; // exit code
  const memory_region region;

private:
  memory<PeTarget>& data_region;
  sys_func_ptr sim_syscall_table[SYSCALL_TABLE_SIZE];
  uint32_t riscv_xlen;
  uint64_t partial_htif_command;
  int htif_parts_received;

  void handle_sim_command(uint32_t command)
  {
    switch (static_cast<SimCommand>(command)) {
    case SimCommand::NEWLINE:
      std::putchar('\n');
      break;
    case SimCommand::TEST_ILM:
      subport_test = SubPortTest::TEST_ILM;
      custom_master_sem.post();
      break;
    case SimCommand::TEST_DLM:
      subport_test = SubPortTest::TEST_DLM;
      custom_master_sem.post();
      break;
    case SimCommand::TEST_HVM:
      subport_test = SubPortTest::TEST_HVM;
      custom_master_sem.post();
      break;
    default:
      if (command >= 0 && command < 256)
        exits = command;
      else
        spdlog::warn("sim_control: unknown command {:#x}", command);
    }
  }

  template<typename T>
  static T unpack(const std::span<uint8_t>& buf)
  {
    T result = 0;
    for (size_t i = 0; i < sizeof(T); ++i)
      result |= static_cast<T>(buf[i]) << (i * 8);
    return result;
  }

  void execute_htif_syscall()
  {
    command_t cmd(partial_htif_command);
    if (cmd.device() != 0 || cmd.cmd() != 0) {
      spdlog::warn("unknown device: #{}", cmd.device());
      return;
    }
    dispatch(cmd);
    partial_htif_command = 0;
    htif_parts_received = 0;
  }

  void handle_htif_64bit_write(const std::span<uint8_t>& buf)
  {
    command_t cmd(unpack<uint64_t>(buf));
    if (cmd.device() == 0 && cmd.cmd() == 0)
      dispatch(cmd);
    else
      spdlog::warn("unknown device: #{}", cmd.device());
  }

  void handle_htif_32bit_low_write(const std::span<uint8_t>& buf)
  {
    partial_htif_command |= unpack<uint32_t>(buf);
    if (++htif_parts_received == HTIF_32BIT_PARTS)
      execute_htif_syscall();
  }

  void handle_htif_32bit_high_write(const std::span<uint8_t>& buf)
  {
    partial_htif_command |= static_cast<uint64_t>(unpack<uint32_t>(buf)) << 32;
    if (++htif_parts_received == HTIF_32BIT_PARTS)
      execute_htif_syscall();
  }

  void dispatch(command_t cmd)
  {
    uint64_t syscall_args[MAGIC_MEM_SIZE];
    auto addr_offset = cmd.payload() - data_region.region.base_address;
    auto src = data_region.data.begin() + addr_offset;

    std::copy(src, src + sizeof(syscall_args),
              reinterpret_cast<uint8_t*>(syscall_args));

    syscall_args[0] = (this->*sim_syscall_table[syscall_args[0]])(
      syscall_args[1], syscall_args[2], syscall_args[3], syscall_args[4],
      syscall_args[5], syscall_args[6], syscall_args[7]);

    std::copy(reinterpret_cast<uint8_t*>(syscall_args),
              reinterpret_cast<uint8_t*>(syscall_args) + sizeof(syscall_args),
              src);
  }
};

